class Solution {
public:
    int minFlipsMonoIncr(string s) {
        int n = s.size();
        int flips = 0;
        int ones = 0;
        for (int i = 0; i < n; i++) {
            if (s[i] == '1') {
                ones++;
            } else {
                flips = min(flips + 1, ones);
            }
        }
        return flips;
    }
};
```
